import React, { useState } from 'react';
import { Save, Eye, EyeOff, ShieldAlert } from 'lucide-react';
import { supabase } from '../../lib/supabase';
import { useAuth } from '../../context/AuthContext';

const ForcePasswordChange: React.FC = () => {
    const { refreshUser, logout } = useAuth();
    const [newPassword, setNewPassword] = useState('');
    const [confirmPassword, setConfirmPassword] = useState('');
    const [showNew, setShowNew] = useState(false);
    const [showConfirm, setShowConfirm] = useState(false);
    const [error, setError] = useState('');
    const [loading, setLoading] = useState(false);

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        setError('');

        if (newPassword !== confirmPassword) {
            setError('Las contraseñas no coinciden.');
            return;
        }

        if (newPassword.length < 6) {
            setError('La contraseña debe tener al menos 6 caracteres.');
            return;
        }

        setLoading(true);
        try {
            // 1. Update password and metadata in Supabase Auth
            const { error: authError } = await supabase.auth.updateUser({
                password: newPassword,
                data: { requires_password_change: false }
            });

            if (authError) throw authError;

            // 2. Update flag in public.user_accounts
            const { data: { user } } = await supabase.auth.getUser();
            if (user) {
                const { error: dbError } = await supabase
                    .from('user_accounts')
                    .update({ requires_password_change: false })
                    .eq('id', user.id);

                if (dbError) throw dbError;
            }

            // 3. Refresh user context to clear the flag
            await refreshUser();
        } catch (err: any) {
            setError(err.message || 'Error al actualizar la contraseña.');
        } finally {
            setLoading(false);
        }
    };

    return (
        <div style={{
            minHeight: '100vh',
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'center',
            background: '#f0f4f8',
            padding: '1rem'
        }}>
            <div className="card" style={{ maxWidth: '400px', width: '100%', padding: '2rem' }}>
                <div style={{ textAlign: 'center', marginBottom: '2rem' }}>
                    <div style={{
                        width: '50px',
                        height: '50px',
                        background: 'rgba(26, 95, 122, 0.1)',
                        borderRadius: '50%',
                        display: 'flex',
                        alignItems: 'center',
                        justifyContent: 'center',
                        margin: '0 auto 1rem'
                    }}>
                        <ShieldAlert className="text-primary" size={28} />
                    </div>
                    <h2 style={{ fontSize: '1.5rem', fontWeight: 700, color: '#1A5F7A' }}>Actualización Obligatoria</h2>
                    <p style={{ color: '#6b7280', marginTop: '0.5rem' }}>
                        Por seguridad, debes establecer una nueva contraseña en tu primer acceso.
                    </p>
                </div>

                <form onSubmit={handleSubmit} className="modal-form">
                    {error && (
                        <div style={{
                            padding: '0.75rem',
                            background: '#fee2e2',
                            color: '#dc2626',
                            borderRadius: '8px',
                            fontSize: '0.85rem',
                            marginBottom: '1rem'
                        }}>
                            {error}
                        </div>
                    )}

                    <div className="form-group relative">
                        <label>Nueva Contraseña</label>
                        <div className="relative">
                            <input
                                type={showNew ? 'text' : 'password'}
                                required
                                value={newPassword}
                                onChange={e => setNewPassword(e.target.value)}
                                placeholder="Mínimo 6 caracteres"
                                style={{ paddingRight: '2.5rem', width: '100%' }}
                            />
                            <button
                                type="button"
                                className="absolute right-3 top-1/2 -translate-y-1/2 text-gray-400 hover:text-gray-600"
                                onClick={() => setShowNew(!showNew)}
                            >
                                {showNew ? <EyeOff size={16} /> : <Eye size={16} />}
                            </button>
                        </div>
                    </div>

                    <div className="form-group relative" style={{ marginTop: '1rem' }}>
                        <label>Confirmar Nueva Contraseña</label>
                        <div className="relative">
                            <input
                                type={showConfirm ? 'text' : 'password'}
                                required
                                value={confirmPassword}
                                onChange={e => setConfirmPassword(e.target.value)}
                                placeholder="Repite la contraseña"
                                style={{ paddingRight: '2.5rem', width: '100%' }}
                            />
                            <button
                                type="button"
                                className="absolute right-3 top-1/2 -translate-y-1/2 text-gray-400 hover:text-gray-600"
                                onClick={() => setShowConfirm(!showConfirm)}
                            >
                                {showConfirm ? <EyeOff size={16} /> : <Eye size={16} />}
                            </button>
                        </div>
                    </div>

                    <button
                        type="submit"
                        className="btn-primary"
                        disabled={loading}
                        style={{ width: '100%', marginTop: '2rem', height: '48px', justifyContent: 'center' }}
                    >
                        {loading ? 'Actualizando...' : (
                            <>
                                <Save size={18} style={{ marginRight: 8 }} />
                                Guardar y Continuar
                            </>
                        )}
                    </button>

                    <button
                        type="button"
                        className="btn-link"
                        onClick={() => logout()}
                        style={{ width: '100%', marginTop: '1rem', color: '#6b7280' }}
                    >
                        Cerrar sesión
                    </button>
                </form>
            </div>
        </div>
    );
};

export default ForcePasswordChange;

import React, { useState } from 'react';
import { X, Lock, Eye, EyeOff, Save } from 'lucide-react';
import { adminResetPassword } from '../../modules/therapists/service';

interface AdminChangePasswordModalProps {
    therapistId: string;
    therapistName: string;
    onClose: () => void;
}

const AdminChangePasswordModal: React.FC<AdminChangePasswordModalProps> = ({ therapistId, therapistName, onClose }) => {
    const [newPassword, setNewPassword] = useState('');
    const [confirmPassword, setConfirmPassword] = useState('');
    const [error, setError] = useState('');
    const [success, setSuccess] = useState('');
    const [loading, setLoading] = useState(false);
    const [showNew, setShowNew] = useState(false);
    const [showConfirm, setShowConfirm] = useState(false);

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        setError('');
        setSuccess('');

        if (newPassword !== confirmPassword) {
            setError('Las contraseñas no coinciden.');
            return;
        }
        if (newPassword.length < 6) {
            setError('La contraseña debe tener al menos 6 caracteres.');
            return;
        }

        setLoading(true);
        try {
            await adminResetPassword(therapistId, newPassword);
            setSuccess(`Contraseña de ${therapistName} actualizada correctamente.`);
            setTimeout(() => onClose(), 1500);
        } catch (err: any) {
            setError(err.message || 'Error al cambiar la contraseña.');
        } finally {
            setLoading(false);
        }
    };

    return (
        <div className="modal-overlay">
            <div className="modal-content" style={{ maxWidth: '420px' }}>
                <div className="modal-header">
                    <div className="flex items-center gap-2">
                        <Lock size={20} className="text-primary" />
                        <h3>Cambiar Contraseña</h3>
                    </div>
                    <button className="btn-icon-round" onClick={onClose}><X size={20} /></button>
                </div>

                <div style={{ padding: '0.5rem 0 1rem', color: '#6b7280', fontSize: '0.9rem' }}>
                    Establecer nueva contraseña para <strong>{therapistName}</strong>
                </div>

                <form className="modal-form" onSubmit={handleSubmit}>
                    {error && <div className="p-3 mb-4 rounded bg-red-50 text-red-600 text-sm">{error}</div>}
                    {success && <div className="p-3 mb-4 rounded bg-green-50 text-green-600 text-sm">{success}</div>}

                    <div className="form-group relative">
                        <label>Nueva Contraseña</label>
                        <input
                            type={showNew ? 'text' : 'password'}
                            required
                            value={newPassword}
                            onChange={e => setNewPassword(e.target.value)}
                            placeholder="Mínimo 6 caracteres"
                            style={{ paddingRight: '2.5rem' }}
                        />
                        <button
                            type="button"
                            className="absolute right-3 top-[34px] text-gray-400 hover:text-gray-600"
                            onClick={() => setShowNew(!showNew)}
                        >
                            {showNew ? <EyeOff size={16} /> : <Eye size={16} />}
                        </button>
                    </div>

                    <div className="form-group relative">
                        <label>Confirmar Contraseña</label>
                        <input
                            type={showConfirm ? 'text' : 'password'}
                            required
                            value={confirmPassword}
                            onChange={e => setConfirmPassword(e.target.value)}
                            placeholder="Repite la contraseña"
                            style={{ paddingRight: '2.5rem' }}
                        />
                        <button
                            type="button"
                            className="absolute right-3 top-[34px] text-gray-400 hover:text-gray-600"
                            onClick={() => setShowConfirm(!showConfirm)}
                        >
                            {showConfirm ? <EyeOff size={16} /> : <Eye size={16} />}
                        </button>
                    </div>

                    <div className="modal-footer mt-6">
                        <button type="button" className="btn-secondary" onClick={onClose} disabled={loading}>
                            Cancelar
                        </button>
                        <button type="submit" className="btn-primary" disabled={loading}>
                            <Save size={16} />
                            {loading ? 'Guardando...' : 'Establecer Contraseña'}
                        </button>
                    </div>
                </form>
            </div>
        </div>
    );
};

export default AdminChangePasswordModal;

import React, { useState } from 'react';
import { X, Lock, Eye, EyeOff, Save } from 'lucide-react';
import { useAuth } from '../../context/AuthContext';
import { changePassword } from '../../modules/therapists/service';

interface ChangePasswordModalProps {
    onClose: () => void;
}

const ChangePasswordModal: React.FC<ChangePasswordModalProps> = ({ onClose }) => {
    const { user } = useAuth();
    const [currentPassword, setCurrentPassword] = useState('');
    const [newPassword, setNewPassword] = useState('');
    const [confirmPassword, setConfirmPassword] = useState('');
    const [error, setError] = useState('');
    const [success, setSuccess] = useState('');
    const [loading, setLoading] = useState(false);

    const [showCurrent, setShowCurrent] = useState(false);
    const [showNew, setShowNew] = useState(false);
    const [showConfirm, setShowConfirm] = useState(false);

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        setError('');
        setSuccess('');

        if (newPassword !== confirmPassword) {
            setError('Las nuevas contraseñas no coinciden.');
            return;
        }

        if (newPassword.length < 6) {
            setError('La nueva contraseña debe tener al menos 6 caracteres.');
            return;
        }

        if (!user || user.role !== 'THERAPIST') {
            setError('Solo los terapeutas pueden cambiar su contraseña por esta vía.');
            return;
        }

        setLoading(true);
        try {
            await changePassword(user.id, currentPassword, newPassword);
            setSuccess('Contraseña actualizada correctamente.');
            setTimeout(() => {
                onClose();
            }, 1500);
        } catch (err: any) {
            setError(err.message || 'Error al cambiar la contraseña.');
        } finally {
            setLoading(false);
        }
    };

    return (
        <div className="modal-overlay">
            <div className="modal-content" style={{ maxWidth: '400px' }}>
                <div className="modal-header">
                    <div className="flex items-center gap-2">
                        <Lock size={20} className="text-primary" />
                        <h3>Cambiar Contraseña</h3>
                    </div>
                    <button className="btn-icon-round" onClick={onClose}><X size={20} /></button>
                </div>

                <form className="modal-form" onSubmit={handleSubmit}>
                    {error && <div className="p-3 mb-4 rounded bg-red-50 text-red-600 text-sm">{error}</div>}
                    {success && <div className="p-3 mb-4 rounded bg-green-50 text-green-600 text-sm">{success}</div>}

                    <div className="form-group relative">
                        <label>Contraseña Actual</label>
                        <input
                            type={showCurrent ? "text" : "password"}
                            required
                            value={currentPassword}
                            onChange={(e) => setCurrentPassword(e.target.value)}
                            style={{ paddingRight: '2.5rem' }}
                        />
                        <button
                            type="button"
                            className="absolute right-3 top-[34px] text-gray-400 hover:text-gray-600"
                            onClick={() => setShowCurrent(!showCurrent)}
                        >
                            {showCurrent ? <EyeOff size={16} /> : <Eye size={16} />}
                        </button>
                    </div>

                    <div className="form-group relative">
                        <label>Nueva Contraseña</label>
                        <input
                            type={showNew ? "text" : "password"}
                            required
                            value={newPassword}
                            onChange={(e) => setNewPassword(e.target.value)}
                            style={{ paddingRight: '2.5rem' }}
                        />
                        <button
                            type="button"
                            className="absolute right-3 top-[34px] text-gray-400 hover:text-gray-600"
                            onClick={() => setShowNew(!showNew)}
                        >
                            {showNew ? <EyeOff size={16} /> : <Eye size={16} />}
                        </button>
                    </div>

                    <div className="form-group relative">
                        <label>Confirmar Nueva Contraseña</label>
                        <input
                            type={showConfirm ? "text" : "password"}
                            required
                            value={confirmPassword}
                            onChange={(e) => setConfirmPassword(e.target.value)}
                            style={{ paddingRight: '2.5rem' }}
                        />
                        <button
                            type="button"
                            className="absolute right-3 top-[34px] text-gray-400 hover:text-gray-600"
                            onClick={() => setShowConfirm(!showConfirm)}
                        >
                            {showConfirm ? <EyeOff size={16} /> : <Eye size={16} />}
                        </button>
                    </div>

                    <div className="modal-footer mt-6">
                        <button type="button" className="btn-secondary" onClick={onClose} disabled={loading}>
                            Cancelar
                        </button>
                        <button type="submit" className="btn-primary" disabled={loading}>
                            <Save size={16} /> {/* Replace with Spinner if preferred */}
                            {loading ? 'Guardando...' : 'Cambiar Contraseña'}
                        </button>
                    </div>
                </form>
            </div>
        </div>
    );
};

export default ChangePasswordModal;

import React, { useState, useEffect } from 'react';
import { useAuth } from '../../context/AuthContext';
import { getIllustrativeAvatar } from '../../modules/therapists/utils';
import { Bell, LogOut, ChevronDown, Clock, LayoutDashboard, Calendar, Users, FileText, ShieldCheck, UserRound } from 'lucide-react';
import './Header.css';
import { useLocation, useNavigate } from 'react-router-dom';
import WorkforceWidget from '../../modules/workforce/WorkforceWidget';
import NotificationPanel from '../notifications/NotificationPanel';
import { getNotifications, getDismissedIds, dismissNotification } from '../../modules/notifications/service';
import type { Notification } from '../../modules/notifications/types';

const Header: React.FC = () => {
    const { user, logout, isRole } = useAuth();
    const location = useLocation();
    const navigate = useNavigate();
    const [isProfileOpen, setIsProfileOpen] = useState(false);
    const [isWorkforceOpen, setIsWorkforceOpen] = useState(false);

    // Notification State
    const [isNotificationsOpen, setIsNotificationsOpen] = useState(false);
    const [notifications, setNotifications] = useState<Notification[]>([]);
    const [unreadCount, setUnreadCount] = useState(0);

    const [showClockInReminder, setShowClockInReminder] = useState(false);

    // Fetch notifications
    useEffect(() => {
        if (user) {
            loadNotifications();
            if (user.role === 'THERAPIST') {
                checkClockInStatus();
            }
        }
        
        const handleWorkforceUpdate = () => {
            if (user?.role === 'THERAPIST') {
                checkClockInStatus();
            }
        };
        
        window.addEventListener('workforce-update', handleWorkforceUpdate);
        return () => window.removeEventListener('workforce-update', handleWorkforceUpdate);
    }, [user, location.pathname]);

    const checkClockInStatus = async () => {
        if (!user || !user.therapistId) return; 
        const { getLiveWorkStats, checkScheduleAdherence } = await import('../../modules/workforce/service');
        const [stats, adherence] = await Promise.all([
            getLiveWorkStats(user.therapistId),
            checkScheduleAdherence(user.therapistId)
        ]);

        if (stats.status === 'offline' && adherence.isAdherent) {
            setShowClockInReminder(true);
        } else {
            setShowClockInReminder(false);
        }
    };

    const loadNotifications = async () => {
        if (!user) return;
        const role = user.role as 'ADMIN' | 'THERAPIST';

        const allNotifs = await getNotifications(role, user.therapistId || user.id);

        // Filtrar las que han sido descartadas hoy
        const dismissedIds = getDismissedIds();
        const filtered = allNotifs.filter(n => !dismissedIds.includes(n.id));

        setNotifications(filtered);
        setUnreadCount(filtered.filter(n => !n.read).length);
    };

    const handleDismiss = (id: string) => {
        dismissNotification(id);
        const updated = notifications.filter(n => n.id !== id);
        setNotifications(updated);
        setUnreadCount(updated.filter(n => !n.read).length);
    };

    const handleMarkAsRead = (id: string) => {
        const updated = notifications.map(n =>
            n.id === id ? { ...n, read: true } : n
        );
        setNotifications(updated);
        setUnreadCount(updated.filter(n => !n.read).length);
    };

    const getPageInfo = () => {
        const path = location.pathname;
        if (path === '/') return { title: 'Dashboard', icon: <span className="header-icon text-secondary"><LayoutDashboard size={24} /></span> };
        if (path.startsWith('/calendar')) return { title: 'Agenda', icon: <span className="header-icon text-primary"><Calendar size={24} /></span> };
        if (path.startsWith('/patients')) return { title: 'Pacientes', icon: <span className="header-icon text-emerald-500"><Users size={24} /></span> };
        if (path.startsWith('/waiting-list')) return { title: 'Lista de Espera', icon: <span className="header-icon text-amber-500"><Clock size={24} /></span> };
        if (path.startsWith('/therapists')) return { title: 'Terapeutas', icon: <span className="header-icon text-indigo-500"><UserRound size={24} /></span> };
        if (path.startsWith('/billing')) return { title: 'Facturación', icon: <span className="header-icon text-blue-500"><FileText size={24} /></span> };
        if (path.startsWith('/admin')) return { title: 'Configuración', icon: <span className="header-icon text-slate-500"><ShieldCheck size={24} /></span> };

        return { title: 'Proyecta CRM', icon: null };
    };

    const { title, icon } = getPageInfo();

    const handleLogout = async () => {
        await logout();
        navigate('/login', { replace: true });
    };

    return (
        <header className="app-header-container">
            {showClockInReminder && (
                <div className="clock-in-reminder-banner">
                    <div className="flex items-center gap-2">
                        <Clock size={16} />
                        <span>No has fichado la entrada todavía. Recuerda registrar tu inicio de jornada.</span>
                    </div>
                    <div className="flex items-center gap-4">
                        <button 
                            style={{
                                backgroundColor: '#854d0e',
                                color: '#fef3c7',
                                padding: '0.4rem 1.25rem',
                                borderRadius: '999px',
                                border: 'none',
                                fontWeight: '700',
                                fontSize: '0.875rem',
                                cursor: 'pointer',
                                boxShadow: '0 2px 5px rgba(133, 77, 14, 0.2)',
                                transition: 'all 0.2s ease',
                                display: 'flex',
                                alignItems: 'center',
                                gap: '0.5rem'
                            }}
                            onMouseEnter={(e) => {
                                e.currentTarget.style.backgroundColor = '#713f12';
                                e.currentTarget.style.transform = 'translateY(-1px)';
                            }}
                            onMouseLeave={(e) => {
                                e.currentTarget.style.backgroundColor = '#854d0e';
                                e.currentTarget.style.transform = 'none';
                            }}
                            onClick={() => {
                                setIsWorkforceOpen(true);
                            }}>
                            Fichar Ahora
                        </button>
                    </div>
                </div>
            )}
            <div className="app-header">
                <div className="header-left">
                    <div className="header-page-info">
                        {icon}
                        <h1 className="page-title">{title}</h1>
                    </div>
                </div>

                <div className="header-right">
                    {/* Workforce Compact Widget - Click to expand */}
                    <div className="header-action-item">
                        <button
                            className="btn-icon-text workforce-trigger"
                            onClick={() => setIsWorkforceOpen(!isWorkforceOpen)}
                        >
                            <Clock size={18} />
                            <span>Fichar</span>
                        </button>
                        {isWorkforceOpen && (
                            <div className="workforce-popover">
                                <WorkforceWidget />
                            </div>
                        )}
                    </div>

                    {/* Notifications */}
                    <div className="header-action-item">
                        <button
                            className="btn-icon-round relative"
                            onClick={() => setIsNotificationsOpen(!isNotificationsOpen)}
                        >
                            <Bell size={20} />
                            {unreadCount > 0 && <span className="notification-badge">{unreadCount}</span>}
                        </button>
                        {isNotificationsOpen && (
                            <div style={{ position: 'absolute', top: '100%', right: 0, zIndex: 9999 }}>
                                <NotificationPanel
                                    notifications={notifications}
                                    onClose={() => setIsNotificationsOpen(false)}
                                    onMarkAsRead={handleMarkAsRead}
                                    onDismiss={handleDismiss}
                                />
                            </div>
                        )}
                    </div>

                    {/* Profile */}
                    <div className="header-profile-container">
                        <button
                            className="header-profile-btn"
                            onClick={() => setIsProfileOpen(!isProfileOpen)}
                        >
                            <div className="avatar small">
                                <img 
                                    src={getIllustrativeAvatar({ fullName: user?.name, avatarUrl: user?.avatarUrl })} 
                                    alt={user?.name} 
                                    style={{ width: '100%', height: '100%', borderRadius: '50%', objectFit: 'cover' }} 
                                />
                            </div>
                            <span className="profile-name">{user?.name}</span>
                            <ChevronDown size={14} className={`transition-transform ${isProfileOpen ? 'rotate-180' : ''}`} />
                        </button>

                        {isProfileOpen && (
                            <div className="profile-dropdown">
                                <div className="dropdown-header">
                                    <p className="font-bold">{user?.name}</p>
                                    <p className="text-xs text-gray-500">{user?.email}</p>
                                    <span className="text-xs" style={{ color: '#1A5F7A', fontWeight: 600 }}>
                                        {isRole('ADMIN') ? '🔑 Admin' : '🩺 Terapeuta'}
                                    </span>
                                </div>
                                <div className="dropdown-divider"></div>
                                <button className="dropdown-item text-red-600" onClick={handleLogout}>
                                    <LogOut size={16} />
                                    <span>Cerrar Sesión</span>
                                </button>
                            </div>
                        )}
                    </div>
                </div>
            </div>
        </header>
    );
};

export default Header;

import React, { useEffect, useState } from 'react';
import { CheckCircle, AlertCircle, Info, X } from 'lucide-react';
import './Toast.css';

export type ToastType = 'success' | 'error' | 'info';

interface ToastProps {
    message: string;
    type: ToastType;
    duration?: number;
    onClose: () => void;
}

const Toast: React.FC<ToastProps> = ({ message, type, duration = 5000, onClose }) => {
    const [isExiting, setIsExiting] = useState(false);

    useEffect(() => {
        const timer = setTimeout(() => {
            handleClose();
        }, duration);

        return () => clearTimeout(timer);
    }, [duration]);

    const handleClose = () => {
        setIsExiting(true);
        setTimeout(onClose, 300); // Wait for animation
    };

    const getIcon = () => {
        switch (type) {
            case 'success': return <CheckCircle size={20} />;
            case 'error': return <AlertCircle size={20} />;
            case 'info': return <Info size={20} />;
        }
    };

    return (
        <div className={`toast-item ${type} ${isExiting ? 'exit' : 'enter'}`}>
            <div className="toast-icon">
                {getIcon()}
            </div>
            <div className="toast-content">
                <p className="toast-message">{message}</p>
            </div>
            <button className="toast-close" onClick={handleClose}>
                <X size={16} />
            </button>
        </div>
    );
};

export default Toast;

import React, { createContext, useContext, useState, useEffect, type ReactNode } from 'react';
import { supabase } from '../lib/supabase';
import type { Session, User as SupabaseUser } from '@supabase/supabase-js';

export type UserRole = 'ADMIN' | 'THERAPIST';

interface User {
    id: string;
    name: string;
    email: string;
    role: UserRole;
    requiresPasswordChange: boolean;
    therapistId?: string;
    avatarUrl?: string;
}

interface AuthContextType {
    user: User | null;
    session: Session | null;
    loading: boolean;
    login: (email: string, password: string) => Promise<User>;
    logout: () => Promise<void>;
    isRole: (role: UserRole) => boolean;
    refreshUser: () => Promise<void>;
}

const AuthContext = createContext<AuthContextType | undefined>(undefined);

// Helper: map Supabase user to app User
// Role is stored in user_metadata.role (set when creating the user in Admin)
const mapUser = (supabaseUser: SupabaseUser): User => {
    const meta = supabaseUser.user_metadata || {};
    const role: UserRole = meta.role?.toUpperCase() === 'ADMIN' ? 'ADMIN' : 'THERAPIST';
    const name = meta.full_name || meta.name || supabaseUser.email?.split('@')[0] || 'Usuario';
    const requiresPasswordChange = meta.requires_password_change === true;

    return {
        id: supabaseUser.id,
        name,
        email: supabaseUser.email || '',
        role,
        requiresPasswordChange,
        therapistId: meta.therapist_id,
        avatarUrl: meta.avatar_url,
    };
}

export const AuthProvider: React.FC<{ children: ReactNode }> = ({ children }) => {
    const [user, setUser] = useState<User | null>(null);
    const [session, setSession] = useState<Session | null>(null);
    const [loading, setLoading] = useState(true);

    useEffect(() => {
        // Get initial session with error handling to prevent infinite loading
        const initAuth = async () => {
            try {
                const { data: { session }, error } = await supabase.auth.getSession();
                if (error) throw error;
                
                setSession(session);
                const initialUser = session?.user ? mapUser(session.user) : null;
                setUser(initialUser);

                // Sync therapistId if missing
                if (initialUser && !initialUser.therapistId) {
                    syncTherapistId(initialUser.id);
                }
            } catch (error) {
                console.error("Initial auth session error:", error);
            } finally {
                setLoading(false);
            }
        };

        initAuth();

        // Listen for auth state changes
        const { data: { subscription } } = supabase.auth.onAuthStateChange((_event, session) => {
            setSession(session);
            const updatedUser = session?.user ? mapUser(session.user) : null;
            setUser(updatedUser);

            if (updatedUser && !updatedUser.therapistId) {
                syncTherapistId(updatedUser.id);
            }
            setLoading(false);
        });

        return () => subscription.unsubscribe();
    }, []);

    const syncTherapistId = async (authId: string) => {
        try {
            // Priority 1: Check user_accounts table
            const { data: account } = await supabase
                .from('user_accounts')
                .select('therapist_id, email')
                .eq('id', authId)
                .maybeSingle();

            if (account?.therapist_id) {
                const { data: tData } = await supabase
                    .from('therapists')
                    .select('avatar_url')
                    .eq('id', account.therapist_id)
                    .maybeSingle();

                setUser(prev => prev ? { 
                    ...prev, 
                    therapistId: account.therapist_id,
                    avatarUrl: tData?.avatar_url || prev.avatarUrl
                } : null);
                return;
            }

            // Priority 2: Fallback to matching by email in therapists table
            const email = account?.email || (await supabase.auth.getUser()).data.user?.email;
            if (email) {
                const { data: therapist } = await supabase
                    .from('therapists')
                    .select('id')
                    .eq('email', email)
                    .maybeSingle();

                if (therapist) {
                    const { data: tData } = await supabase
                        .from('therapists')
                        .select('avatar_url')
                        .eq('id', therapist.id)
                        .maybeSingle();

                    setUser(prev => prev ? { 
                        ...prev, 
                        therapistId: therapist.id,
                        avatarUrl: tData?.avatar_url || prev.avatarUrl 
                    } : null);
                }
            }
        } catch (e) {
            console.error("Error syncing therapist ID:", e);
        }
    };

    const login = async (email: string, password: string): Promise<User> => {
        const { data, error } = await supabase.auth.signInWithPassword({ email, password });
        if (error) throw error;
        const mappedUser = mapUser(data.user);
        setUser(mappedUser); // Pre-set user for immediate use
        return mappedUser;
    };

    const logout = async () => {
        await supabase.auth.signOut();
    };

    const refreshUser = async () => {
        const { data: { user: supabaseUser } } = await supabase.auth.getUser();
        if (supabaseUser) {
            setUser(mapUser(supabaseUser));
        }
    };

    const isRole = (role: UserRole) => user?.role === role;

    return (
        <AuthContext.Provider value={{ user, session, loading, login, logout, isRole, refreshUser }}>
            {children}
        </AuthContext.Provider>
    );
};

export const useAuth = () => {
    const context = useContext(AuthContext);
    if (!context) {
        throw new Error('useAuth must be used within an AuthProvider');
    }
    return context;
};

import React, { createContext, useContext, useState, useCallback } from 'react';
import type { ReactNode } from 'react';
import Toast from '../components/ui/Toast';
import type { ToastType } from '../components/ui/Toast';

interface ToastItem {
    id: string;
    message: string;
    type: ToastType;
    duration?: number;
}

interface ToastContextType {
    showToast: (message: string, type: ToastType, duration?: number) => void;
}

const ToastContext = createContext<ToastContextType | undefined>(undefined);

export const ToastProvider: React.FC<{ children: ReactNode }> = ({ children }) => {
    const [toasts, setToasts] = useState<ToastItem[]>([]);

    const showToast = useCallback((message: string, type: ToastType, duration?: number) => {
        const id = Math.random().toString(36).substr(2, 9);
        setToasts(prev => [...prev, { id, message, type, duration }]);
    }, []);

    const removeToast = useCallback((id: string) => {
        setToasts(prev => prev.filter(toast => toast.id !== id));
    }, []);

    return (
        <ToastContext.Provider value={{ showToast }}>
            {children}
            <div className="toast-container">
                {toasts.map(toast => (
                    <Toast
                        key={toast.id}
                        message={toast.message}
                        type={toast.type}
                        duration={toast.duration}
                        onClose={() => removeToast(toast.id)}
                    />
                ))}
            </div>
        </ToastContext.Provider>
    );
};

export const useToast = () => {
    const context = useContext(ToastContext);
    if (!context) {
        throw new Error('useToast must be used within a ToastProvider');
    }
    return context;
};

