import "jsr:@supabase/functions-js/edge-runtime.d.ts";
import { createClient } from 'npm:@supabase/supabase-js@2';

const corsHeaders = {
    'Access-Control-Allow-Origin': '*',
    'Access-Control-Allow-Headers': 'authorization, x-client-info, apikey, content-type',
};

Deno.serve(async (req) => {
    if (req.method === 'OPTIONS') {
        return new Response('ok', { headers: corsHeaders });
    }

    try {
        const supabaseUrl = Deno.env.get('SUPABASE_URL') ?? '';
        const anonKey = Deno.env.get('SUPABASE_ANON_KEY') ?? '';
        const serviceRoleKey = Deno.env.get('SUPABASE_SERVICE_ROLE_KEY') ?? '';

        const authHeader = req.headers.get('Authorization');
        if (!authHeader) {
            console.error('Missing Authorization header');
            return new Response(JSON.stringify({ error: 'Missing authorization header' }), {
                headers: { ...corsHeaders, 'Content-Type': 'application/json' },
                status: 401,
            });
        }

        const userClient = createClient(supabaseUrl, anonKey, {
            global: { headers: { Authorization: authHeader } }
        });

        const { data: { user: adminUser }, error: userError } = await userClient.auth.getUser();

        if (userError || !adminUser) {
            console.error('JWT Verification Error:', userError?.message || 'No user found');
            return new Response(JSON.stringify({ 
                error: 'Unauthorized', 
                details: userError?.message || 'Token verification failed' 
            }), {
                headers: { ...corsHeaders, 'Content-Type': 'application/json' },
                status: 401,
            });
        }

        console.log(`Authenticated as: ${adminUser.email} (${adminUser.id})`);

        const rawRole = (adminUser.user_metadata?.role || '').toString().trim().toUpperCase();
        let isAdmin = rawRole === 'ADMIN' || rawRole === 'ADMINISTRATOR';

        const supabaseService = createClient(supabaseUrl, serviceRoleKey);

        if (!isAdmin) {
            const { data: userData, error: dbRoleError } = await supabaseService
                .from('user_accounts')
                .select('role')
                .eq('id', adminUser.id)
                .single();

            if (dbRoleError) console.warn('Error fetching DB role:', dbRoleError.message);

            const dbRole = (userData?.role || '').toString().trim().toUpperCase();
            if (dbRole === 'ADMIN' || dbRole === 'ADMINISTRATOR') {
                isAdmin = true;
            }
        }

        if (!isAdmin) {
            console.error(`Access Denied: User ${adminUser.email} is not an admin`);
            return new Response(JSON.stringify({ error: 'Forbidden: Only administrators can manage attendance for others' }), {
                headers: { ...corsHeaders, 'Content-Type': 'application/json' },
                status: 403,
            });
        }

        // --- NEW FIX: Ensure admin is in user_accounts to avoid FK and RLS issues ---
        console.log('Self-repair: ensuring admin account exists in user_accounts...');
        await supabaseService.from('user_accounts').upsert({
            id: adminUser.id,
            email: adminUser.email,
            full_name: adminUser.user_metadata?.full_name || 'Administrador',
            role: 'Admin',
            status: 'Active'
        }, { onConflict: 'id' });
        // ------------------------------------------------------------------------

        const payload = await req.json();
        const { action, id, record, therapist_id } = payload;

        let result;
        if (action === 'insert') {
            const { data, error } = await supabaseService.from('attendance').insert(record).select().single();
            if (error) throw error;
            result = data;
        } else if (action === 'update') {
            const { data, error } = await supabaseService.from('attendance').update(record).eq('id', id).select().single();
            if (error) throw error;
            result = data;
        } else if (action === 'delete') {
            const { error } = await supabaseService.from('attendance').delete().eq('id', id);
            if (error) throw error;
            result = { success: true };
        } else if (action === 'cleanup') {
            if (!therapist_id) throw new Error('Therapist ID required for cleanup');

            // Fetch all non-work attendance for this therapist
            const { data: allAtt, error: fetchError } = await supabaseService
                .from('attendance')
                .select('id, start_time, end_time, type, notes')
                .eq('therapist_id', therapist_id)
                .neq('type', 'work');

            if (fetchError) throw fetchError;

            const seen = new Set();
            const toDelete: string[] = [];

            (allAtt || []).forEach(v => {
                // Key: normalized time and type
                const key = `${v.start_time}-${v.end_time || ''}-${v.type}`;
                if (seen.has(key)) {
                    toDelete.push(v.id);
                } else {
                    seen.add(key);
                }
            });

            if (toDelete.length > 0) {
                const { error: delError } = await supabaseService
                    .from('attendance')
                    .delete()
                    .in('id', toDelete);
                if (delError) throw delError;
            }

            result = { deletedCount: toDelete.length };
        } else {
            throw new Error('Invalid action');
        }

        return new Response(JSON.stringify({ success: true, data: result }), {
            headers: { ...corsHeaders, 'Content-Type': 'application/json' },
            status: 200,
        });
    } catch (error: any) {
        console.error('Attendance Management Error:', error.message || error);
        return new Response(JSON.stringify({ 
            error: error.message || 'Internal Server Error',
            details: error
        }), {
            headers: { ...corsHeaders, 'Content-Type': 'application/json' },
            status: 400,
        });
    }
});

import { serve } from "https://deno.land/std@0.177.0/http/server.ts"
import { createClient } from "https://esm.sh/@supabase/supabase-js@2.39.0"

serve(async (_req) => {
  try {
    const supabaseUrl = Deno.env.get('SUPABASE_URL')
    const supabaseKey = Deno.env.get('SUPABASE_SERVICE_ROLE_KEY')
    const makeWebhookUrl = Deno.env.get('MAKE_WEBHOOK_URL_REMINDERS')

    if (!supabaseUrl || !supabaseKey || !makeWebhookUrl) {
      throw new Error("Missing environment variables")
    }

    const supabase = createClient(supabaseUrl, supabaseKey)

    // Calculamos las fechas para buscar citas en las próximas 24 horas
    const now = new Date()
    const tomorrow = new Date(now.getTime() + 24 * 60 * 60 * 1000)

    const { data: appointments, error } = await supabase
      .from('appointments')
      .select(`
        id,
        patient_id,
        patient_name,
        start_time,
        notificacion_recordatorio_enviada,
        status,
        patients ( phone )
      `)
      .gte('start_time', now.toISOString())
      .lte('start_time', tomorrow.toISOString())
      .eq('notificacion_recordatorio_enviada', false)
      .eq('status', 'Programada')

    if (error) throw error

    console.log(`Found ${appointments?.length || 0} appointments to send reminders for.`)

    const results = []

    for (const appt of appointments || []) {
      const phone = appt.patients?.phone

      if (!phone) {
        console.warn(`No phone number for patient ${appt.patient_name} (${appt.patient_id}). Skipping.`)
        continue
      }

      // Enviar a Make.com
      const payload = {
        id_cita: appt.id,
        nombre_paciente: appt.patient_name,
        telefono: phone,
        fecha_hora_cita: appt.start_time
      }

      const response = await fetch(makeWebhookUrl, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(payload)
      })

      if (response.ok) {
        // Actualizar en BBDD
        const { error: updateError } = await supabase
          .from('appointments')
          .update({ notificacion_recordatorio_enviada: true })
          .eq('id', appt.id)

        if (updateError) {
          console.error(`Error updating DB for appointment ${appt.id}:`, updateError)
        } else {
          results.push({ id: appt.id, status: 'sent' })
        }
      } else {
        console.error(`Error sending to Make for appointment ${appt.id}: HTTP ${response.status}`)
        results.push({ id: appt.id, status: 'error' })
      }
    }

    return new Response(JSON.stringify({ success: true, processed: results.length, results }), {
      headers: { "Content-Type": "application/json" }
    })
  } catch (error: any) {
    console.error("Error in send-reminders function:", error)
    return new Response(JSON.stringify({ error: error.message }), {
      status: 500,
      headers: { "Content-Type": "application/json" }
    })
  }
})

import "jsr:@supabase/functions-js/edge-runtime.d.ts";

const corsHeaders = {
  'Access-Control-Allow-Origin': '*',
  'Access-Control-Allow-Headers': 'authorization, x-client-info, apikey, content-type',
};

Deno.serve(async (req) => {
  if (req.method === 'OPTIONS') {
    return new Response('ok', { headers: corsHeaders });
  }

  if (req.method === 'GET') {
    return new Response(JSON.stringify({ status: 'ok' }), {
      headers: { ...corsHeaders, 'Content-Type': 'application/json' }
    });
  }

  try {
    const { therapistName, month, totalHours, _signatureImage, totalDays, pdfBase64 } = await req.json();
    console.log(`Enviando reporte firmado para: ${therapistName}, mes: ${month}`);

    if (!pdfBase64) {
        throw new Error("No PDF base64 data provided in request");
    }

    // Extract base64 part if it contains the data URI prefix
    const pdfAttachmentBase64 = pdfBase64.includes(',') ? pdfBase64.split(',')[1] : pdfBase64;

    // @ts-expect-error dynamic import of npm package in Deno
    const nodemailer = await import('npm:nodemailer');

    const monthLabel = new Date(`${month}-15`).toLocaleDateString('es-ES', { month: 'long', year: 'numeric' });

    // ── Send Email ──────────────────────────────────────────────────────────
    const SMTP_HOST = Deno.env.get('SMTP_HOST') ?? "mail.centroproyecta.es";
    const SMTP_PORT = parseInt(Deno.env.get('SMTP_PORT') ?? "465");
    const SMTP_USER = Deno.env.get('SMTP_USER') ?? "info@centroproyecta.es";
    const SMTP_PASS = Deno.env.get('SMTP_PASS') ?? "";

    const transporter = nodemailer.createTransport({
      host: SMTP_HOST,
      port: SMTP_PORT,
      secure: SMTP_PORT === 465,
      auth: {
        user: SMTP_USER,
        pass: SMTP_PASS,
      },
      tls: { rejectUnauthorized: false }
    });

    let htmlBody = '<div style="font-family: \'Segoe UI\', sans-serif; color: #333; max-width: 700px; margin: 0 auto; border: 1px solid #e0e0e0; border-radius: 8px; overflow: hidden;">';
    htmlBody += '<div style="background-color: #1A5F7A; padding: 25px; text-align: center;">';
    htmlBody += '<h1 style="margin: 0; color: white; font-size: 22px;">Reporte de Jornada Laboral Firmado</h1>';
    htmlBody += '</div>';
    htmlBody += '<div style="padding: 30px;">';
    htmlBody += `<p>Hola,</p>`;
    htmlBody += `<p><strong>${therapistName}</strong> ha firmado su reporte de jornada laboral correspondiente a <strong>${monthLabel}</strong>.</p>`;
    htmlBody += '<table style="width: 100%; border-collapse: collapse; margin: 20px 0;">';
    htmlBody += `<tr><td style="padding: 8px; border-bottom: 1px solid #eee; font-weight: bold;">Total Horas</td><td style="padding: 8px; border-bottom: 1px solid #eee;">${totalHours}h</td></tr>`;
    htmlBody += `<tr><td style="padding: 8px; border-bottom: 1px solid #eee; font-weight: bold;">Días con Actividad</td><td style="padding: 8px; border-bottom: 1px solid #eee;">${totalDays}</td></tr>`;
    htmlBody += `<tr><td style="padding: 8px; font-weight: bold;">Fecha de Firma</td><td style="padding: 8px;">${new Date().toLocaleDateString('es-ES')}</td></tr>`;
    htmlBody += '</table>';
    htmlBody += '<p>Se adjunta el reporte firmado en formato PDF.</p>';
    htmlBody += '<br><p>Atentamente,<br>Sistema Proyecta CRM</p>';
    htmlBody += '</div>';
    htmlBody += '<div style="background-color: #f8f9fa; padding: 15px; text-align: center; color: #95a5a6; font-size: 11px; border-top: 1px solid #eee;">';
    htmlBody += '<p style="margin: 0;">Mensaje automático — Centro Infantil Proyecta, S.L.</p></div></div>';

    const filename = `Reporte_Jornada_${therapistName.replace(/\s+/g, '_')}_${month}.pdf`;

    const info = await transporter.sendMail({
      from: `"Centro Proyecta" <${SMTP_USER}>`,
      to: 'info@centroproyecta.es',
      subject: `Reporte Firmado - ${therapistName} - ${monthLabel}`,
      html: htmlBody,
      attachments: [{
        filename,
        content: pdfAttachmentBase64,
        encoding: 'base64'
      }]
    });

    console.log("Email de reporte enviado:", info.messageId);

    return new Response(
      JSON.stringify({ success: true, messageId: info.messageId }),
      { headers: { ...corsHeaders, 'Content-Type': 'application/json' } }
    );
  } catch (error: any) {
    console.error("Error en send-signed-report:", error.message);
    return new Response(
      JSON.stringify({ success: false, error: error.message }),
      { status: 200, headers: { ...corsHeaders, 'Content-Type': 'application/json' } }
    );
  }
});

import { serve } from "https://deno.land/std@0.177.0/http/server.ts"
import { createClient } from "https://esm.sh/@supabase/supabase-js@2.39.0"

serve(async (req) => {
  try {
    const supabaseUrl = Deno.env.get('SUPABASE_URL')
    const supabaseKey = Deno.env.get('SUPABASE_SERVICE_ROLE_KEY')
    const makeWebhookUrl = Deno.env.get('MAKE_WEBHOOK_URL_REVIEWS')

    if (!supabaseUrl || !supabaseKey || !makeWebhookUrl) {
      throw new Error("Missing environment variables")
    }

    // El body viene del Database Webhook de Supabase
    const payload = await req.json()
    console.log("Webhook payload received:", payload)

    // Solo nos importa si es un UPDATE en appointments
    if (payload.type !== 'UPDATE' || payload.table !== 'appointments') {
      return new Response(JSON.stringify({ message: "Ignored: Not an appointment update" }), { status: 200 })
    }

    const newRecord = payload.record
    const oldRecord = payload.old_record

    // Si cambió a 'Finalizada' y antes NO lo era
    if (newRecord.status === 'Finalizada' && oldRecord.status !== 'Finalizada') {
      const supabase = createClient(supabaseUrl, supabaseKey)

      // Obtener el teléfono del paciente
      const { data: patient, error } = await supabase
        .from('patients')
        .select('phone')
        .eq('id', newRecord.patient_id)
        .single()

      if (error) throw error

      if (!patient?.phone) {
        console.warn(`Patient ${newRecord.patient_id} has no phone. Skipping review request.`)
        return new Response(JSON.stringify({ message: "Ignored: No phone number" }), { status: 200 })
      }

      // Enviar a Make.com
      const makePayload = {
        id_paciente: newRecord.patient_id,
        nombre_paciente: newRecord.patient_name,
        telefono: patient.phone
      }

      console.log("Sending review request to Make:", makePayload)

      const response = await fetch(makeWebhookUrl, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(makePayload)
      })

      if (!response.ok) {
        throw new Error(`Make.com responded with status ${response.status}`)
      }

      return new Response(JSON.stringify({ success: true, sent: true }), { status: 200 })
    }

    return new Response(JSON.stringify({ message: "Ignored: Status is not Finalizada or hasn't changed" }), { status: 200 })

  } catch (error: any) {
    console.error("Error processing review webhook:", error)
    return new Response(JSON.stringify({ error: error.message }), { status: 500 })
  }
})
